-lg-2"><select id="filter_sloc" class="form-control"><option value=""><?=wh_h(wh_t('common_all', 'Semua'));?></option><?php foreach($slocs as $s){?><option value="<?=intval($s->id);?>" data-plant-id="<?=intval($s->plant_id);?>"><?=htmlspecialchars($s->plant_code.' / '.$s->storage_code.' - '.$s->storage_name,ENT_QUOTES,'UTF-8');?></option><?php }?></select></div><label class="control-label col-lg-1">Bin</label><div class="col-lg-3"><select id="filter_bin" class="form-control"><option value=""><?=wh_h(wh_t('common_all', 'Semua'));?></option><?php foreach($bins as $b){?><option value="<?=intval($b->id);?>" data-storage-location-id="<?=intval($b->storage_location_id);?>"><?=htmlspecialchars($b->storage_code.' / '.$b->bin_code.' - '.$b->bin_name,ENT_QUOTES,'UTF-8');?></option><?php }?></select></div></div><div class="form-group"><label class="control-label col-lg-2"><?=wh_h(wh_t('warehouse_material', 'Material'));?></label><div class="col-lg-3"><select id="filter_material" class="form-control"></select></div><label class="control-label col-lg-1"><?=wh_h(wh_t('common_search', 'Search'));?></label><div class="col-lg-4"><input id="filter_keyword" class="form-control" placeholder="Adjustment no / reason / user"></div><div class="col-lg-2"><button id="btn_filter_msa" class="btn btn-primary"><i class="fa fa-filter"></i> <?=wh_h(wh_t('common_filter', 'Filter'));?></button> <button id="btn_excel_msa" class="btn btn-success"><i class="fa fa-file-excel-o"></i></button></div></div></form></div></div>
