    <div class="row"><div class="col-md-2 form-group"><label class="required-label"><?=wh_h(wh_t('warehouse_stock_type', 'Stock Type'));?></label><select name="stock_type" id="stock_type" class="form-control" required><option>UNRESTRICTED</option><option>QUALITY</option><option>BLOCKED</option></select></div><div class="col-md-3 form-group"><label class="required-label">Reason Code</label><select name="reason_code" id="reason_code" class="form-control" required><option value="COUNT_CORRECTION">Count Correction</option><option value="DAMAGE_CORRECTION">Damage Correction</option><option value="SYSTEM_CORRECTION">System Correction</option><option value="CUSTOMS_RECON">Customs Reconciliation</option><option value="OTHER">Other</option></select></div><div class="col-md-7 form-group"><label>Reason Text</label><input name="reason_text" id="reason_text" class="form-control" placeholder="Penjelasan approval / koreksi"></div></div>
