  </div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal"><?=wh_h(wh_t('common_cancel', 'Cancel'));?></button><button type="submit" class="btn btn-primary"><i class="fa fa-save"></i> <?=wh_h(wh_t('common_post', 'Post'));?> Adjustment</button></div></form></div></div></div>
