<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
function msaError(m){$('.isi_warning_delete').text(m||'Manual stock adjustment gagal diproses.');$('.error_data_delete').fadeIn();}
function msaFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),adjustment_type:$('#filter_adjustment_type').val(),plant_id:$('#filter_plant').val(),storage_location_id:$('#filter_sloc').val(),storage_bin_id:$('#filter_bin').val(),stock_type:$('#filter_stock_type').val(),material_code:$('#filter_material').val(),keyword:$('#filter_keyword').val()};}
function rowNo(){ $('#msa_item_body tr').each(function(i){$(this).find('.line-no').text(i+1);}); }
function addRow(){
  var tr=$('<tr><td class="line-no"></td><td><select name="material_code[]" class="form-control item-material"></select><input type="hidden" name="material_name[]" class="item-name"></td><td><input class="form-control input-sm text-right system-qty" readonly value="0.00000"><div class="msa-stock-preview"></div></td><td><input type="number" step="0.00001" min="0.00001" name="qty[]" class="form-control input-sm text-right item-qty" required></td><td><input name="uom[]" class="form-control input-sm item-uom" readonly></td><td><input type="number" step="0.00001" min="0" name="price[]" class="form-control input-sm text-right item-price" value="0"></td><td><input class="form-control input-sm text-right item-amount" readonly value="0.00"></td><td><input name="line_remarks[]" class="form-control input-sm"></td><td><button type="button" class="btn btn-danger btn-xs btn-remove-item"><i class="fa fa-trash"></i></button></td></tr>');
  $('#msa_item_body').append(tr); rowNo();
  tr.find('.item-material').select2({width:'100%',dropdownParent:$('#modal_msa'),placeholder:'Cari material...',minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/manual_stock_adjustment/manual_stock_adjustment_action.php?act=material_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||'',adjustment_type:$('#adjustment_type').val(),plant_id:$('#plant_id').val(),storage_location_id:$('#storage_location_id').val(),storage_bin_id:$('#storage_bin_id').val(),stock_type:$('#stock_type').val()};},processResults:function(d){return{results:d.results||[]};}}}).on('select2:select',function(e){var d=e.params.data,tr=$(this).closest('tr');tr.find('.item-name').val(d.material_name||'');tr.find('.item-uom').val(d.uom||'');loadStock(tr);});
}
function loadStock(tr){var mat=tr.find('.item-material').val();if(!mat)return;$.post('<?=base_admin();?>modul/manual_stock_adjustment/manual_stock_adjustment_action.php?act=stock_qty',{material_code:mat,plant_id:$('#plant_id').val(),storage_location_id:$('#storage_location_id').val(),storage_bin_id:$('#storage_bin_id').val(),stock_type:$('#stock_type').val()},function(r){var s=parseFloat(r.stock||0);tr.find('.system-qty').val(s.toFixed(5));tr.find('.msa-stock-preview').text('Stock available: '+s.toFixed(5));},'json');}
function calc(tr){var q=parseFloat(tr.find('.item-qty').val()||0),p=parseFloat(tr.find('.item-price').val()||0);tr.find('.item-amount').val((q*p).toFixed(2));}
$(function(){
  if($.fn.datepicker){$('.msa-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}
  if($.fn.select2){$('#filter_adjustment_type,#filter_stock_type,#filter_plant,#filter_sloc,#filter_bin,#plant_id,#storage_location_id,#storage_bin_id,#adjustment_type,#stock_type,#reason_code').select2({width:'100%'});$('#filter_material').select2({width:'100%',allowClear:true,placeholder:'Cari material...',minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/manual_stock_adjustment/manual_stock_adjustment_action.php?act=material_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||'',adjustment_type:$('#filter_adjustment_type').val()||'INCREASE',plant_id:$('#filter_plant').val(),storage_location_id:$('#filter_sloc').val(),storage_bin_id:$('#filter_bin').val(),stock_type:$('#filter_stock_type').val()};},processResults:function(d){return{results:d.results||[]};}}});}
  var dt=$('#dtb_manual_stock_adjustment').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=json_encode(wh_t('common_export_data', 'Export Data'));?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[6,7],className:'text-right'}],ajax:{url:'<?=base_admin();?>modul/manual_stock_adjustment/manual_stock_adjustment_data.php',type:'post',data:function(d){$.extend(d,msaFilters());},error:function(xhr){console.log(xhr.responseText);msaError('Data adjustment gagal dimuat.');}}});
  $('#btn_filter_msa').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_excel_msa').click(function(){window.location='<?=base_admin();?>modul/manual_stock_adjustment/manual_stock_adjustment_action.php?act=excel&'+$.param(msaFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
  $('#btn_open_msa').click(function(){$('#form_msa')[0].reset();$('#document_date,#posting_date').val('<?=$today;?>');$('#msa_item_body').empty();$('#plant_id,#storage_location_id,#storage_bin_id').val('').trigger('change');$('#adjustment_type').val('INCREASE').trigger('change');$('#stock_type').val('UNRESTRICTED').trigger('change');addRow();$('#modal_msa').modal({backdrop:'static',keyboard:false});});
  $('#btn_add_item_msa').click(addRow);$(document).on('click','.btn-remove-item',function(){$(this).closest('tr').remove();rowNo();});$(document).on('keyup change','.item-qty,.item-price',function(){calc($(this).closest('tr'));});
  $('#adjustment_type,#plant_id,#storage_location_id,#storage_bin_id,#stock_type').change(function(){$('#msa_item_body tr').each(function(){loadStock($(this));});});
  $('#form_msa').submit(function(e){e.preventDefault();if($('#msa_item_body tr').length<1){msaError('Minimal 1 item wajib diisi.');return;}if(!confirm('Posting manual stock adjustment sekarang?'))return;var btn=$(this).find('button[type=submit]');btn.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=wh_h(wh_t('common_post', 'Post'));?>ing...');$.post('<?=base_admin();?>modul/manual_stock_adjustment/manual_stock_adjustment_action.php?act=post',$(this).serialize(),function(r){if(r.status==='good'){$('#modal_msa').modal('hide');alert('Adjustment berhasil: '+r.adjustment_no);dt.draw(false);}else msaError(r.error_message);},'json').fail(function(xhr){msaError(xhr.responseText);}).always(function(){btn.prop('disabled',false).html('<i class="fa fa-save"></i> <?=wh_h(wh_t('common_post', 'Post'));?> Adjustment');});});
  $(document).on('click','.btn-msa-detail',function(){$.post('<?=base_admin();?>modul/manual_stock_adjustment/manual_stock_adjustment_action.php?act=detail',{id:$(this).data('id')},function(html){$('#msa_detail_body').html(html);$('#modal_msa_detail').modal('show');});});
});
</script>
